import{_ as t,o as l,c as e,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Actor","description":"","frontmatter":{},"headers":[],"relativePath":"Unreal Engine/Actor.md","filePath":"Unreal Engine/Actor.md","lastUpdated":null}'),r={name:"Unreal Engine/Actor.md"};function n(c,o,s,a,d,g){return l(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="actor" tabindex="-1">Actor <a class="header-anchor" href="#actor" aria-label="Permalink to &quot;Actor&quot;">​</a></h1><p><strong>Actor是所有可以放置到关卡中对象的基类。</strong></p><h2 id="actor的生命周期" tabindex="-1">Actor的生命周期 <a class="header-anchor" href="#actor的生命周期" aria-label="Permalink to &quot;Actor的生命周期&quot;">​</a></h2><p>Actor的初始化分为多个步骤。以下是按照执行顺序列出的一些关键回调：</p><ol><li><code>UObject::PostLoad</code><ul><li>对于<strong>静态放置在关卡中的Actor</strong>，不论在编辑器还是运行时，都会触发这个回调。</li><li><strong>动态实例化的Actor则不会触发</strong>。</li></ul></li><li><code>UActorComponent::OnComponentCreated</code><ul><li>对于<strong>动态实例化的Actor</strong>，不论在编辑器还是在运行时，实例化后，其身上的<strong>C++组件</strong>会触发这个回调。</li><li>而<strong>蓝图创建的组件</strong>则不会触发这个回调。它会在蓝图构造该组件时触发。</li><li>对于<strong>静态放置在关卡中的Actor则不会触发</strong>。</li></ul></li><li><code>AActor::PreRegisterAllComponents</code><ul><li>对于拥有<strong>C++根组件</strong>的Actor，不论是静态放置的，还是动态实例化的，都会触发这个回调。</li><li>对于<strong>蓝图类的Actor</strong>，并且没有<strong>C++根组件</strong>的Actor，它会在蓝图构造时触发。</li></ul></li><li><code>UActorComponent::RegisterComponent</code><ul><li>所有的组件在此时注册，不论在编辑器还是运行时。</li><li>它会创建<strong>物理资源</strong>和<strong>渲染资源</strong>。</li><li>这个函数可能会<strong>分帧执行</strong>，但是总会<strong>在 <code>PreRegisterAllComponents</code> 之后</strong>。</li><li>这个方法可能会在 <code>UnRegisterComponent</code> 调用后，从 <code>World</code> 移除后再次触发。</li></ul></li><li><code>AActor::PostRegisterAllComponents</code><ul><li>不论在编辑器还是运行时的Actor都会调用这个方法。</li><li>组件注册完成后调用。</li></ul></li><li><code>AActor::PostActorCreated</code><ul><li>不论在编辑器还是运行时，这个方法会<strong>在构造函数之前调用</strong>。</li><li><strong>静态放置在关卡中的Actor不会触发</strong>。</li></ul></li><li><code>AActor::UserConstructionScript</code><ul><li>当蓝图实现了构造函数时调用。</li></ul></li><li><code>AActor::OnConstruction</code><ul><li>在 <code>ExecuteConstruction</code> 的最后调用，该方法调用了蓝图的构造函数。</li><li>这个方法会在<strong>蓝图的组件创建并注册完成后</strong>触发。</li><li>这个方法只在<strong>动态实例化的Actor身上触发</strong>，在编辑器可能会在修改蓝图时提前返回。</li></ul></li><li><code>AActor::PreInitializeComponents</code><ul><li>这个方法会在<strong>组件的 <code>InitializeComponent</code> 方法之前</strong>调用。</li><li>这个方法只会在 <code>gameplay</code>，以及<strong>编辑器下特定的预览窗口中</strong>调用。</li></ul></li><li><code>UActorComponent::Activate</code><ul><li>这个方法只会在<strong>bAutoActivate设置为真</strong>时触发。</li><li>这个方法可能会在<strong>手动设置bAutoActivate为真</strong>时再次触发。</li></ul></li><li><code>UActorComponent::InitializeComponent</code><ul><li>这个方法会在<strong>bWantsInitializeComponentSet</strong>时触发。</li><li>这个方法在每次 <code>gameplay session</code> 只会触发一次。</li></ul></li><li><code>AActor::PostInitializeComponents</code><ul><li>这个方法在组件初始化完成后触发。</li><li>这个方法只会在 <code>gameplay</code>，以及<strong>编辑器下特定的预览窗口中</strong>调用。</li></ul></li><li><code>AActor::BeginPlay</code><ul><li>会在 <code>level</code> 开始tick时调用。只会在 <code>gameplay</code> 时执行。</li><li>通常在 <code>PostInitializeComponents</code> 之后调用，但是可能会<strong>被网络或者Child Actor所推迟</strong>。</li></ul></li></ol><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/Unreal_Engine_Actor_1.png" alt=""></p>',6)])])}const p=t(r,[["render",n]]);export{u as __pageData,p as default};
